        $c.gus.cfEnableObj(em_alngpierHh,false);
        $c.gus.cfEnableObj(em_offpierDt,false);
        $c.gus.cfEnableObj(em_offpierHh,false);
	  	$c.gus.cfEnableObj(button_Save1,false);
	  	$c.gus.cfEnableObj(button_Save2,false);
	  	$c.gus.cfEnableObj(button_Save3,false);
	  	$c.gus.cfEnableObj(btn_Add,false);
	  	$c.gus.cfEnableObj(btn_Delete,false);
	  	$c.gus.cfEnableObj(btn_Cancel,false);
	  	$c.gus.cfEnableObj(btn_Add1,false);
	  	$c.gus.cfEnableObj(btn_Delete1,false);
	  	$c.gus.cfEnableObj(btn_Cancel1,false);
	}

    // 그리드 rowIndex 0 포커스
    gr_containerAgreementVolumeResults.setFocusedCell(0, 0);
    gr_containerAgreementVolume.setFocusedCell(0, 0);
    gr_containerCVSVComparison.setFocusedCell(0, 0);
